        <p>{{ currentDate }} · 欢迎回来，管理员</p>
      </div>
      <div class="quick-actions">
        <el-button type="primary" size="small" icon="el-icon-plus" @click="$router.push('/product/add')">添加商品</el-button>
        <el-button size="small" icon="el-icon-s-order" @click="$router.push('/order/list')">查看订单</el-button>
      </div>
    </div>

    <!-- 4 个核心指标卡片 -->
    <el-row :gutter="20" class="stat-cards">
      <el-col :xs="24" :sm="12" :md="6" v-for="card in statCards" :key="card.key">
        <div class="stat-card" :class="card.color">
          <div class="stat-card-inner">
            <div class="stat-info">
              <div class="stat-label">{{ card.label }}</div>
              <div class="stat-value">{{ card.value }}</div>
              <div class="stat-compare">
                <i :class="card.trendUp ? 'el-icon-top' : 'el-icon-bottom'" />
                {{ card.compareText }}
              </div>
            </div>
            <div class="stat-icon">
              <i :class="card.icon" />
            </div>
          </div>
        </div>
      </el-col>
    </el-row>

    <!-- 待处理 + 库存预警 -->
    <el-row :gutter="20" class="alert-row">
      <el-col :xs="24" :md="12">
        <el-card class="alert-card" shadow="hover">
          <div slot="header"><i class="el-icon-bell" /> 待处理事项</div>
          <div class="alert-grid">
            <div class="alert-item" @click="$router.push('/order/list?status=10')">
              <span class="alert-num warning">{{ pending.payCount }}</span>
              <span class="alert-label">待付款</span>
            </div>
            <div class="alert-item" @click="$router.push('/order/list?status=20')">
              <span class="alert-num primary">{{ pending.deliverCount }}</span>
              <span class="alert-label">待发货</span>
            </div>
            <div class="alert-item" @click="$router.push('/return/list')">
              <span class="alert-num danger">{{ pending.refundCount }}</span>
              <span class="alert-label">待退款</span>
            </div>
            <div class="alert-item">
              <span class="alert-num success">{{ pending.commentCount }}</span>
              <span class="alert-label">待回复评论</span>
            </div>
          </div>
        </el-card>
      </el-col>
      <el-col :xs="24" :md="12">
        <el-card class="alert-card" shadow="hover">
          <div slot="header"><i class="el-icon-warning-outline" /> 库存预警</div>
          <div class="stock-list">
            <div class="stock-item" v-for="item in lowStockProducts" :key="item.id">
              <span class="stock-name">{{ item.name }}</span>
              <span class="stock-spec" v-if="item.spec">{{ item.spec }}</span>
              <el-tag :type="item.stock <= 5 ? 'danger' : 'warning'" size="mini">
                仅剩 {{ item.stock }}
              </el-tag>
            </div>
            <div class="stock-empty" v-if="lowStockProducts.length === 0">
              暂无库存预警商品
            </div>
          </div>
        </el-card>
      </el-col>
    </el-row>

    <!-- 销售趋势图 + 热销排行 -->
    <el-row :gutter="20">
      <el-col :xs="24" :md="14">
        <el-card class="chart-card" shadow="hover">
          <div slot="header" class="chart-header">
            <span>销售趋势</span>
            <el-radio-group v-model="chartRange" size="mini" @change="updateChart">
              <el-radio-button label="week">近7天</el-radio-button>
              <el-radio-button label="month">近30天</el-radio-button>
            </el-radio-group>
          </div>
          <div ref="salesChart" class="chart-body" />
