        <el-card class="rank-card" shadow="hover">
          <div slot="header"><span>热销商品 TOP5</span></div>
          <div class="rank-list">
            <div class="rank-item" v-for="(item, i) in topProducts" :key="item.id">
              <div class="rank-num" :class="'rank-' + (i + 1)">{{ i + 1 }}</div>
              <img :src="item.cover || defaultCover" class="rank-cover" />
              <div class="rank-info">
                <div class="rank-name">{{ item.name }}</div>
                <el-progress :percentage="item.salesPct" :stroke-width="6" :show-text="false" />
              </div>
              <div class="rank-sales">售 {{ item.sales }}</div>
            </div>
          </div>
        </el-card>
      </el-col>
    </el-row>

    <!-- 最新订单 -->
    <el-card class="order-card" shadow="hover">
      <div slot="header">
        <span>最新订单</span>
        <el-button type="text" style="float:right" @click="$router.push('/order/list')">全部订单 →</el-button>
      </div>
      <el-table :data="recentOrders" stripe>
        <el-table-column prop="orderNo" label="订单号" min-width="170" />
        <el-table-column prop="userName" label="客户" min-width="100" />
        <el-table-column prop="totalAmount" label="金额" min-width="90">
          <template slot-scope="s">¥{{ s.row.totalAmount }}</template>
        </el-table-column>
        <el-table-column prop="status" label="状态" min-width="80">
          <template slot-scope="s">
            <el-tag :type="statusType(s.row.status)" size="small">{{ statusText(s.row.status) }}</el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="createTime" label="时间" min-width="150" />
        <el-table-column label="操作" min-width="80" fixed="right">
          <template slot-scope="s">
            <el-button type="text" size="mini" @click="$router.push('/order/detail/' + s.row._id)">详情</el-button>
          </template>
        </el-table-column>
      </el-table>
      <el-empty v-if="!pageLoading && recentOrders.length === 0" description="暂无数据" />
    </el-card>
  </div>
</template>

<script>
import * as echarts from 'echarts'
import statisticsApi from '@/api/statistics'

const STATUS_MAP = {
  10: { text: '待付款', type: 'info' },
  20: { text: '待发货', type: 'warning' },
  30: { text: '已发货', type: 'primary' },
  40: { text: '已完成', type: 'success' },
  0:  { text: '已取消', type: 'danger' }
}

export default {
  name: 'Dashboard',
  data() {
    return {
      pageLoading: true,
      currentDate: '',
      chartRange: 'week',
      statCards: [
        { key: 'orders', label: '今日订单', value: 0, icon: 'el-icon-s-order', color: 'blue', trendUp: true, compareText: '较昨日 +12%' },
        { key: 'sales', label: '今日销售额', value: '¥0', icon: 'el-icon-s-goods', color: 'green', trendUp: true, compareText: '较昨日 +8%' },
        { key: 'users', label: '累计用户', value: 0, icon: 'el-icon-user', color: 'orange', trendUp: true, compareText: '较上月 +32' },
        { key: 'products', label: '在售商品', value: 0, icon: 'el-icon-shopping-bag-1', color: 'red', trendUp: false, compareText: '缺货 3 款' }
      ],
      pending: { payCount: 0, deliverCount: 0, refundCount: 0, commentCount: 0 },
      lowStockProducts: [],
      topProducts: [],
      recentOrders: [],
      defaultCover: 'data:image/svg+xml;base64,PHN2ZyB3aWR0aD0iNjAiIGhlaWdodD0iNjAiIHhtbG5zPSJodHRwOi8vd3d3LnczLm9yZy8yMDAwL3N2ZyI+PHJlY3Qgd2lkdGg9IjYwIiBoZWlnaHQ9IjYwIiBmaWxsPSIjZjBmMGYwIi8+PHRleHQgeD0iMzAiIHk9IjM1IiB0ZXh0LWFuY2hvcj0ibWlkZGxlIiBmaWxsPSIjY2NjIiBmb250LXNpemU9IjEyIj7wnI2vPC90ZXh0Pjwvc3ZnPg=='
    }
  },
  mounted() {
    this.currentDate = new Date().toLocaleDateString('zh-CN', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' })
    this.loadAll()
  },
  methods: {
    async loadAll() {
      this.pageLoading = true
      try {
        const res = await statisticsApi.getDashboard()
        if (res && res.code === 0 && res.data) {
          this.applyData(res.data)
        } else {
          this.$message.warning('API 暂不可用，展示模拟数据')
          this.loadMock()
        }
      } catch {
        this.$message.warning('API 暂不可用，展示模拟数据')
        this.loadMock()
      }
      this.pageLoading = false
      this.$nextTick(() => this.renderChart())
    },
    applyData(d) {
      this.statCards[0].value = d.todayOrders || 0
      this.statCards[1].value = '¥' + (d.todaySales || 0)
      this.statCards[2].value = d.totalUsers || 0
      this.statCards[3].value = d.totalProducts || 0
      this.pending = { payCount: d.pendingPay || 0, deliverCount: d.pendingDeliver || 0, refundCount: d.pendingRefund || 0, commentCount: d.pendingComment || 0 }
      this.lowStockProducts = d.lowStockProducts || []
      if (d.topProducts) this.topProducts = d.topProducts.map((p, i) => ({ ...p, salesPct: this.calcPct(p.sales, d.topProducts) }))
      if (d.recentOrders) this.recentOrders = d.recentOrders
    },
    loadMock() {
      this.statCards[0].value = 24; this.statCards[1].value = '¥4,280'; this.statCards[2].value = 1892; this.statCards[3].value = 86
      this.pending = { payCount: 5, deliverCount: 8, refundCount: 2, commentCount: 3 }
      this.lowStockProducts = [
        { id: '1', name: '西湖龙井 特级', spec: '50g', stock: 3 },
        { id: '2', name: '金骏眉', spec: '100g', stock: 5 },
        { id: '3', name: '福鼎白毫银针', spec: '100g', stock: 8 }
      ]
      const top = [
        { id: '1', name: '西湖龙井 明前特级', cover: '', sales: 198 },
        { id: '2', name: '信阳毛尖 特级', cover: '', sales: 156 },
        { id: '3', name: '武夷山大红袍', cover: '', sales: 143 },
        { id: '4', name: '安溪铁观音 清香型', cover: '', sales: 127 },
        { id: '5', name: '普洱茶 熟茶 357g', cover: '', sales: 112 }
      ]
      this.topProducts = top.map(p => ({ ...p, salesPct: this.calcPct(p.sales, top) }))
      this.recentOrders = [
        { _id: '1', orderNo: 'T20260520001', userName: '张先生', totalAmount: 258, status: 10, createTime: '2026-05-20 10:23:45' },
        { _id: '2', orderNo: 'T20260520002', userName: '李女士', totalAmount: 198, status: 20, createTime: '2026-05-20 09:15:30' },
        { _id: '3', orderNo: 'T20260519001', userName: '王先生', totalAmount: 356, status: 30, createTime: '2026-05-19 14:20:10' },
        { _id: '4', orderNo: 'T20260519002', userName: '赵女士', totalAmount: 175, status: 40, createTime: '2026-05-19 11:05:22' },
        { _id: '5', orderNo: 'T20260518001', userName: '孙先生', totalAmount: 420, status: 40, createTime: '2026-05-18 16:30:45' }
      ]
      this.renderChartMock()
    },
    calcPct(sales, arr) {
      const max = Math.max(...arr.map(a => a.sales), 1)
      return Math.round((sales / max) * 100)
    },
    renderChart() {
      if (!this.$refs.salesChart) return
      if (this.chartInstance) this.chartInstance.dispose()
      this.chartInstance = echarts.init(this.$refs.salesChart)
      const data = this.chartRange === 'week'
        ? { x: ['5/14', '5/15', '5/16', '5/17', '5/18', '5/19', '5/20'], s: [3200, 2800, 3600, 4200, 3800, 5100, 4280], o: [12, 10, 15, 18, 14, 22, 24] }
        : { x: Array.from({ length: 30 }, (_, i) => `${i + 1}日`), s: Array.from({ length: 30 }, () => Math.floor(Math.random() * 5000 + 2000)), o: Array.from({ length: 30 }, () => Math.floor(Math.random() * 30 + 5)) }
      this.chartInstance.setOption({
        tooltip: { trigger: 'axis' },
        legend: { data: ['销售额', '订单数'], bottom: 0 },
        grid: { left: '3%', right: '4%', bottom: '12%', top: '8%', containLabel: true },
        xAxis: { type: 'category', boundaryGap: false, data: data.x, axisLine: { lineStyle: { color: '#ddd' } } },
        yAxis: [
          { type: 'value', name: '销售额(¥)', nameTextStyle: { color: '#999' }, splitLine: { lineStyle: { color: '#f5f5f5' } } },
          { type: 'value', name: '订单数', nameTextStyle: { color: '#999' }, splitLine: { show: false } }
        ],
        series: [
          { name: '销售额', type: 'line', smooth: true, data: data.s,
            itemStyle: { color: '#9c6e21' },
            areaStyle: { color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [{ offset: 0, color: 'rgba(156,110,33,0.25)' }, { offset: 1, color: 'rgba(156,110,33,0.02)' }]) } },
          { name: '订单数', type: 'line', smooth: true, yAxisIndex: 1, data: data.o,
            itemStyle: { color: '#67C23A' },
            areaStyle: { color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [{ offset: 0, color: 'rgba(103,194,58,0.2)' }, { offset: 1, color: 'rgba(103,194,58,0.02)' }]) } }
        ]
      })
    },
    renderChartMock() { this.$nextTick(() => this.renderChart()) },
    updateChart() { this.renderChart() },
    statusType(s) { return (STATUS_MAP[s] || {}).type || 'info' },
    statusText(s) { return (STATUS_MAP[s] || {}).text || '未知' }
  },
  beforeDestroy() {
    if (this.chartInstance) this.chartInstance.dispose()
  }
}
</script>

