  .rank-num { width: 22px; height: 22px; line-height: 22px; text-align: center; border-radius: 4px; font-size: 12px; font-weight: 700; margin-right: 12px; background: #f0f0f0; color: #999;
    &.rank-1 { background: #e6a23c; color: #fff; }
